class Solution:
    def concatHex36(self, n: int) -> str:
        def toHex(num):
            return hex(num)[2:].upper()
        def toHex36(num):
            digits = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ"
            result = ""
            while num > 0:
                digit = digits[num % 36]
                result = digit + result
                num //= 36
            return result
        return toHex(n * n) + toHex36(n * n * n)
```
